# GLSL pixel shader for particle simulation
# Set this as the text of a Text DAT wired to the GLSL TOP
shader_code = '''
uniform float uDeltaTime;
uniform float uGravity;
uniform float uDamping;

layout(location = 0) out vec4 fragPosition;

void main()
{
    vec2 uv = vUV.st;
    vec4 pos = texture(sTD2DInputs[0], uv);   // previous position
    vec4 vel = texture(sTD2DInputs[1], uv);   // velocity

    // Apply gravity
    vel.y -= uGravity * uDeltaTime;

    // Apply damping
    vel.xyz *= uDamping;

    // Euler integration
    pos.xyz += vel.xyz * uDeltaTime;

    // Reset particles that fall below ground
    if (pos.y < -1.0) {
        pos.xyz = vec3(0.0);
    }

    fragPosition = pos;
}
'''
op('/project1/glsl_sim_shader').text = shader_code
